dateDisabled() {
  // Returns a function for validating if a date is within range
  // We grab this variables first to ensure a new function ref
  // is generated when the props value changes
  // We do this as we need to trigger the calendar computed prop
  // to update when these props update
  const rangeFn = this.dateOutOfRange
  // Return the function ref
  return date => {
    // Handle both `YYYY-MM-DD` and `Date` objects
    date = parseYMD(date)
    const ymd = formatYMD(date)
    return !!(rangeFn(date) || this.computedDateDisabledFn(ymd, date))
  }
}

dropdownClasses() {
  const { block, split } = this
  return [
    this.directionClass,
    this.boundaryClass,
    {
      show: this.visible,
      // The 'btn-group' class is required in `split` mode for button alignment
      // It needs also to be applied when `block` is disabled to allow multiple
      // dropdowns to be aligned one line
      'btn-group': split || !block,
      // When `block` is enabled and we are in `split` mode the 'd-flex' class
      // needs to be applied to allow the buttons to stretch to full width
      'd-flex': block && split
    }
  ]
}

render(h, { children, data, props }) {
  let transProps = props.transProps
  if (!isPlainObject(transProps)) {
    transProps = props.noFade ? NO_FADE_PROPS : FADE_PROPS
    if (props.appear) {
      // Default the appear classes to equal the enter classes
      transProps = {
        ...transProps,
        appear: true,
        appearClass: transProps.enterClass,
        appearActiveClass: transProps.enterActiveClass,
        appearToClass: transProps.enterToClass
      }
    }
  }
  transProps = {
    mode: props.mode,
    ...transProps,
    // We always need `css` true
    css: true
  }

  const dataCopy = { ...data }
  delete dataCopy.props
  return h(
    'transition',
    // Any transition event listeners will get merged here
    mergeData(dataCopy, { props: transProps }),
    children
  )
}

export function initDirectiveInstance(
  el: HTMLElement & Record<string, unknown>,
  propertyName: string,
  uid: number,
  binding: DirectiveBinding
): DirectiveInstanceState {
  // Initialize UID namespace for this directive
  const elWithProps = el as Record<string, unknown>
  elWithProps[propertyName] = elWithProps[propertyName] ?? Object.create(null)

  // Store per-instance state with JSON cache for change detection
  const state: DirectiveInstanceState = {
    binding: JSON.stringify([binding.modifiers, binding.value]),
    destroying: false,
  }

  ;(elWithProps[propertyName] as Record<string, unknown>)[uid] = state
  return state
}

