async prepare(quasarConf, target) {
  this.#ctx = quasarConf.ctx

  const { cacheProxy } = quasarConf.ctx

  this.runtimeEnv = this.#buildRuntimeEnv(quasarConf)

  const source = this.#resolveSource()
  const { capVersion } = await cacheProxy.getModule('capCli')

  // The user's source is the authoritative config. Quasar passes its runtime info
  // to the Capacitor CLI process via env. The user's config file reads it via
  // defineCapacitorConfig and applies dev-time defaults at config-load time.
  log(`Using capacitor.config.${source.ext}`)
  await this.#updateSSL(quasarConf, target, capVersion)
}

export async function transformHtml(template, quasarConf) {
  let html = renderTemplate(
    template,
    quasarConf.htmlVariables,
    templateCompileOpts
  )

  // should be dev only
  if (quasarConf.metaConf.vueDevtools) {
    html = injectVueDevtools(html, quasarConf.metaConf.vueDevtools)
  }

  html = html.replace(
    entryPointMarkup,
    (quasarConf.ctx.mode.ssr ? entryPointMarkup : attachMarkup) +
      quasarConf.metaConf.entryScript.tag
  )

  // publicPath will be handled by Vite middleware
  // if src/href are not relative, which is what we need
  if (quasarConf.build.publicPath) {
    html = injectPublicPath(html, '/')
  }

  if (!quasarConf.ctx.mode.ssr && quasarConf.build.minify) {
    html = await minify(html, quasarConf.build.htmlMinifyOptions)
  }

  return html
}

export function getNodePackager(folder = appPaths.appDir) {
  const projectPackageManager = getProjectPackageManager(folder)

  // if the project folder uses a supported package manager
  // and it is installed on this machine then use it
  if (projectPackageManager !== void 0 && projectPackageManager.isInstalled()) {
    return projectPackageManager
  }

  // otherwise, use the first installed package manager
  for (const pm of packageManagersList) {
    if (pm.isInstalled()) {
      return pm
    }
  }

  fatal('Please install Yarn, PNPM, NPM or Bun before running this command.\n')
}

function calculateSliceStart() {
  const currentPage = props.modelValue;
  const chunkSize = props.maxSize;
  const currentChunkStart = sliceStart.value;
  const currentChunkEnd = currentChunkStart + chunkSize;
  if (currentPage > currentChunkEnd) {
    const lastChunkStart = props.totalPage - chunkSize;
    if (currentPage > lastChunkStart) {
      sliceStart.value = lastChunkStart;
    } else {
      sliceStart.value = currentPage - 1;
    }
  } else if (currentPage < currentChunkStart + 1) {
    if (currentPage > chunkSize) {
      sliceStart.value = currentPage - chunkSize;
    } else {
      sliceStart.value = 0;
    }
  }
}

export function transform(root: RootNode, options: TransformOptions): void {
  const context = createTransformContext(root, options)
  traverseNode(root, context)
  if (options.hoistStatic) {
    cacheStatic(root, context)
  }
  if (!options.ssr) {
    createRootCodegen(root, context)
  }
  // finalize meta information
  root.helpers = new Set([...context.helpers.keys()])
  root.components = [...context.components]
  root.directives = [...context.directives]
  root.imports = context.imports
  root.hoists = context.hoists
  root.temps = context.temps
  root.cached = context.cached
  root.transformed = true

  if (__COMPAT__) {
    root.filters = [...context.filters!]
  }
}

function preprocess(
  { source, filename, preprocessOptions }: SFCTemplateCompileOptions,
  preprocessor: PreProcessor,
): string {
  // Consolidate exposes a callback based API, but the callback is in fact
  // called synchronously for most templating engines. In our case, we have to
  // expose a synchronous API so that it is usable in Jest transforms (which
  // have to be sync because they are applied via Node.js require hooks)
  let res: string = ''
  let err: Error | null = null

  preprocessor.render(
    source,
    { filename, ...preprocessOptions },
    (_err, _res) => {
      if (_err) err = _err
      res = _res
    },
  )

  if (err) throw err
  return res
}

export function fileToScope(
  ctx: TypeResolveContext,
  filename: string,
  asGlobal = false,
): TypeScope {
  const cache = asGlobal ? fileToGlobalScopeCache : fileToScopeCache
  const cached = cache.get(filename)
  if (cached) {
    return cached
  }
  // fs should be guaranteed to exist here
  const fs = resolveFS(ctx)!
  const source = fs.readFile(filename) || ''
  const body = parseFile(filename, source, fs, ctx.options.babelParserPlugins)
  const scope = new TypeScope(filename, source, 0, recordImports(body))
  recordTypes(ctx, body, scope, asGlobal)
  cache.set(filename, scope)
  return scope
}

export function patchClass(
  el: Element,
  value: string | null,
  isSVG: boolean,
): void {
  // directly setting className should be faster than setAttribute in theory
  // if this is an element during a transition, take the temporary transition
  // classes into account.
  const transitionClasses = (el as ElementWithTransition)[vtcKey]
  if (transitionClasses) {
    value = (
      value ? [value, ...transitionClasses] : [...transitionClasses]
    ).join(' ')
  }
  if (value == null) {
    el.removeAttribute('class')
  } else if (isSVG) {
    el.setAttribute('class', value)
  } else {
    el.className = value
  }
}

function internalSearchCheck(searchTerm, key, value, seen, depth) {
  let match = false
  let result
  if (key === '_custom') {
    key = value.display
    value = value.value
  }
  (result = specialTokenToString(value)) && (value = result)
  if (key && compare(key, searchTerm)) {
    match = true
    seen.set(value, true)
  }
  else if (seen.has(value)) {
    match = seen.get(value)
  }
  else if (Array.isArray(value)) {
    seen.set(value, null)
    match = internalSearchArray(value, searchTerm, seen, depth)
    seen.set(value, match)
  }
  else if (isPlainObject(value)) {
    seen.set(value, null)
    match = internalSearchObject(value, searchTerm, seen, depth)
    seen.set(value, match)
  }
  else if (compare(value, searchTerm)) {
    match = true
    seen.set(value, true)
  }
  return match
}

export function* generateModifiers(
	options: TemplateCodegenOptions,
	ctx: TemplateCodegenContext,
	prop: CompilerDOM.DirectiveNode,
	propertyName: string = 'modifiers',
): Generator<Code> {
	const { modifiers } = prop;
	if (!modifiers.length) {
		return;
	}
	const startOffset = modifiers[0]!.loc.start.offset - 1;
	const endOffset = modifiers.at(-1)!.loc.end.offset;
	const token = yield* startBoundary('template', startOffset, codeFeatures.verification);
	yield propertyName;
	yield endBoundary(token, endOffset);
	yield `: { `;
	for (const mod of modifiers) {
		yield* generateObjectProperty(
			options,
			ctx,
			mod.content,
			mod.loc.start.offset,
			codeFeatures.withoutHighlight,
		);
		yield `: true, `;
	}
	yield `}, `;
}

function* generateIdentifier(
	options: TemplateCodegenOptions,
	ctx: TemplateCodegenContext,
	prop: CompilerDOM.DirectiveNode,
): Generator<Code> {
	const rawName = 'v-' + prop.name;
	const startOffset = prop.loc.start.offset;
	const token = yield* startBoundary('template', startOffset, codeFeatures.verification);
	yield names.directives;
	yield `.`;
	yield* generateCamelized(
		rawName,
		'template',
		prop.loc.start.offset,
		{
			...codeFeatures.withoutHighlightAndCompletion,
			verification: options.vueCompilerOptions.checkUnknownDirectives && !isBuiltInDirective(prop.name),
		},
	);
	if (!isBuiltInDirective(prop.name)) {
		ctx.recordComponentAccess('template', camelize(rawName), prop.loc.start.offset);
	}
	yield endBoundary(token, startOffset + rawName.length);
}

export function normalizeRecordProps(
  record: RouteRecordRaw
): Record<string, _RouteRecordProps> {
  const propsObject = {} as Record<string, _RouteRecordProps>
  // props does not exist on redirect records, but we can set false directly
  const props = record.props || false
  if ('component' in record) {
    propsObject.default = props
  } else {
    // NOTE: we could also allow a function to be applied to every component.
    // Would need user feedback for use cases
    for (const name in record.components)
      propsObject[name] = typeof props === 'object' ? props[name] : props
  }

  return propsObject
}

export async function addParamParserToMap(
  file: string,
  folder: string,
  dtsDir: string,
  paramParsersMap: ParamParsersMap
): Promise<void> {
  const fileName = parsePathe(file).name
  const name = camelCase(fileName)
  // TODO: could be simplified to only one import that starts with / for vite
  const absolutePath = resolve(folder, file)
  const source = await fs.readFile(absolutePath, 'utf8')
  paramParsersMap.set(fileName, {
    name,
    typeName: `Param_${name}`,
    absolutePath,
    relativePath: relative(dtsDir, absolutePath),
    isRaw: isRawParamParserSource(source, absolutePath),
  })
}

export function resolveFolderOptions(
  globalOptions: ResolvedOptions,
  folderOptions: RoutesFolderOption
): RoutesFolderOptionResolved {
  const extensions = overrideOption(
    globalOptions.extensions,
    folderOptions.extensions
  )
  const filePatterns = overrideOption(
    globalOptions.filePatterns,
    folderOptions.filePatterns
  )

  return {
    src: path.resolve(globalOptions.root, folderOptions.src),
    pattern: appendExtensionListToPattern(
      filePatterns,
      // also override the extensions if the folder has a custom extensions
      extensions
    ),
    path: folderOptions.path || '',
    extensions,
    filePatterns,
    exclude: overrideOption(globalOptions.exclude, folderOptions.exclude).map(
      p => (p.startsWith('**') ? p : resolve(p))
    ),
  }
}

function canNeverBeRef(node: Node, userReactiveImport: string): boolean {
  if (isCallOf(node, userReactiveImport)) {
    return true
  }
  switch (node.type) {
    case 'UnaryExpression':
    case 'BinaryExpression':
    case 'ArrayExpression':
    case 'ObjectExpression':
    case 'FunctionExpression':
    case 'ArrowFunctionExpression':
    case 'UpdateExpression':
    case 'ClassExpression':
    case 'TaggedTemplateExpression':
      return true
    case 'SequenceExpression':
      return canNeverBeRef(
        node.expressions[node.expressions.length - 1],
        userReactiveImport
      )
    default:
      if (node.type.endsWith('Literal')) {
        return true
      }
      return false
  }
}

export function resolveConstructorOptions(Ctor: typeof Component) {
  let options = Ctor.options
  if (Ctor.super) {
    const superOptions = resolveConstructorOptions(Ctor.super)
    const cachedSuperOptions = Ctor.superOptions
    if (superOptions !== cachedSuperOptions) {
      // super option changed,
      // need to resolve new options.
      Ctor.superOptions = superOptions
      // check if there are any late-modified/attached options (#4976)
      const modifiedOptions = resolveModifiedOptions(Ctor)
      // update base extend options
      if (modifiedOptions) {
        extend(Ctor.extendOptions, modifiedOptions)
      }
      options = Ctor.options = mergeOptions(superOptions, Ctor.extendOptions)
      if (options.name) {
        options.components[options.name] = Ctor
      }
    }
  }
  return options
}

function (method) {
  // cache original method
  const original = arrayProto[method]
  def(arrayMethods, method, function mutator(...args) {
    const result = original.apply(this, args)
    const ob = this.__ob__
    let inserted
    switch (method) {
      case 'push':
      case 'unshift':
        inserted = args
        break
      case 'splice':
        inserted = args.slice(2)
        break
    }
    if (inserted) ob.observeArray(inserted)
    // notify change
    if (__DEV__) {
      ob.dep.notify({
        type: TriggerOpTypes.ARRAY_MUTATION,
        target: this,
        key: method
      })
    } else {
      ob.dep.notify()
    }
    return result
  })
}
